// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Exchange the shared admin password for an admin session
	// (POST /api/v1/admin/login)
	AdminLogin(ctx context.Context, request AdminLoginRequestObject) (AdminLoginResponseObject, error)
	// Revoke the supplied admin refresh token
	// (POST /api/v1/admin/logout)
	AdminLogout(ctx context.Context, request AdminLogoutRequestObject) (AdminLogoutResponseObject, error)
	// List players with effective leaderboard stats
	// (GET /api/v1/admin/players)
	ListAdminPlayers(ctx context.Context, request ListAdminPlayersRequestObject) (ListAdminPlayersResponseObject, error)
	// Stream admin player list invalidation events
	// (GET /api/v1/admin/players/events)
	StreamAdminPlayerEvents(ctx context.Context, request StreamAdminPlayerEventsRequestObject) (StreamAdminPlayerEventsResponseObject, error)
	// Soft-delete an idle player
	// (DELETE /api/v1/admin/players/{id})
	DeleteAdminPlayer(ctx context.Context, request DeleteAdminPlayerRequestObject) (DeleteAdminPlayerResponseObject, error)
	// Rename a player and override their leaderboard stats
	// (PUT /api/v1/admin/players/{id})
	UpdateAdminPlayer(ctx context.Context, request UpdateAdminPlayerRequestObject) (UpdateAdminPlayerResponseObject, error)
	// List player audit events
	// (GET /api/v1/admin/players/{id}/audit)
	ListAdminPlayerAudit(ctx context.Context, request ListAdminPlayerAuditRequestObject) (ListAdminPlayerAuditResponseObject, error)
	// Rotate the admin session
	// (POST /api/v1/admin/refresh)
	AdminRefresh(ctx context.Context, request AdminRefreshRequestObject) (AdminRefreshResponseObject, error)
	// List all tasks (admin view, includes flag)
	// (GET /api/v1/admin/tasks)
	ListTasks(ctx context.Context, request ListTasksRequestObject) (ListTasksResponseObject, error)
	// Create a task
	// (POST /api/v1/admin/tasks)
	CreateTask(ctx context.Context, request CreateTaskRequestObject) (CreateTaskResponseObject, error)
	// Delete a task
	// (DELETE /api/v1/admin/tasks/{id})
	DeleteTask(ctx context.Context, request DeleteTaskRequestObject) (DeleteTaskResponseObject, error)
	// Read a task by id
	// (GET /api/v1/admin/tasks/{id})
	GetTask(ctx context.Context, request GetTaskRequestObject) (GetTaskResponseObject, error)
	// Update a task (partial update is allowed via PATCH semantics)
	// (PUT /api/v1/admin/tasks/{id})
	UpdateTask(ctx context.Context, request UpdateTaskRequestObject) (UpdateTaskResponseObject, error)
	// Upload a source-file ZIP (≤ 100 MB) and store it in SeaweedFS
	// (POST /api/v1/admin/tasks/{id}/source)
	UploadTaskSource(ctx context.Context, request UploadTaskSourceRequestObject) (UploadTaskSourceResponseObject, error)
	// Read a duel state (for reconnect)
	// (GET /api/v1/duels/{id})
	GetDuel(ctx context.Context, request GetDuelRequestObject) (GetDuelResponseObject, error)
	// Top-50 leaderboard
	// (GET /api/v1/leaderboard)
	GetLeaderboard(ctx context.Context, request GetLeaderboardRequestObject) (GetLeaderboardResponseObject, error)
	// Register or refresh a player session
	// (POST /api/v1/players/join)
	JoinPlayer(ctx context.Context, request JoinPlayerRequestObject) (JoinPlayerResponseObject, error)
	// Clear the current player session cookie
	// (POST /api/v1/players/logout)
	LogoutPlayer(ctx context.Context, request LogoutPlayerRequestObject) (LogoutPlayerResponseObject, error)
	// Resolve the current player session
	// (GET /api/v1/players/me)
	GetMe(ctx context.Context, request GetMeRequestObject) (GetMeResponseObject, error)
	// Liveness + dependency readiness
	// (GET /health)
	HealthCheck(ctx context.Context, request HealthCheckRequestObject) (HealthCheckResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

